package com.multilanglearner.data.repository

import android.content.Context
import com.multilanglearner.data.db.dao.RegulationDao
import com.multilanglearner.data.db.entity.UserRegulation
import com.multilanglearner.domain.model.RegulationCountry
import com.multilanglearner.domain.model.RegulationItem
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.flow.first
import kotlinx.serialization.json.*
import javax.inject.Inject
import javax.inject.Singleton

@Singleton
class RegulationRepository @Inject constructor(
    @ApplicationContext private val context: Context,
    private val dao: RegulationDao
) {
    private val json = Json { ignoreUnknownKeys = true }

    /** Load built-in regulations from assets + user regulations from DB */
    suspend fun getAll(): List<RegulationCountry> {
        // Load built-in from raw resource
        val builtIn = loadBuiltIn()
        val userRegs = dao.getAll().first()

        // Merge user regulations into built-in
        val countryMap = mutableMapOf<String, RegulationCountry>()
        for (country in builtIn) {
            countryMap[country.code] = country
        }
        for (reg in userRegs) {
            val existing = countryMap[reg.countryCode]
            val newItem = RegulationItem(id = reg.id, title = reg.title, content = reg.content, isUser = true)
            if (existing != null) {
                countryMap[reg.countryCode] = existing.copy(items = existing.items + newItem)
            } else {
                countryMap[reg.countryCode] = RegulationCountry(
                    code = reg.countryCode, name = reg.countryName,
                    lang = reg.countryLang, items = listOf(newItem)
                )
            }
        }
        return countryMap.values.toList()
    }

    suspend fun addItem(code: String, name: String, lang: String, title: String, content: String) {
        dao.insert(UserRegulation(countryCode = code, countryName = name, countryLang = lang, title = title, content = content))
    }

    suspend fun deleteItem(id: Long) = dao.deleteById(id)
    suspend fun deleteCountry(code: String) = dao.deleteByCountry(code)

    private fun loadBuiltIn(): List<RegulationCountry> {
        return try {
            val text = context.assets.open("regulations.json").bufferedReader().readText()
            val jsonObj = json.parseToJsonElement(text).jsonObject
            jsonObj.entries.map { (code, value) ->
                val obj = value.jsonObject
                RegulationCountry(
                    code = code,
                    name = obj["name"]?.jsonPrimitive?.contentOrNull ?: code,
                    lang = obj["lang"]?.jsonPrimitive?.contentOrNull ?: "en-US",
                    items = obj["items"]?.jsonArray?.map { item ->
                        val itemObj = item.jsonObject
                        RegulationItem(
                            title = itemObj["title"]?.jsonPrimitive?.contentOrNull ?: "",
                            content = itemObj["content"]?.jsonPrimitive?.contentOrNull ?: ""
                        )
                    } ?: emptyList()
                )
            }
        } catch (e: Exception) {
            emptyList()
        }
    }
}
```

